<?php require 'header.php';
$where='1'; $params=[]; $title='Tất cả sản phẩm';
if(!empty($_GET['cat'])){ $st=$pdo->prepare('SELECT id,name FROM categories WHERE slug=?'); $st->execute([$_GET['cat']]); $cat=$st->fetch(); if($cat){$where='category_id=?';$params=[$cat['id']];$title=$cat['name'];}}
$min=$_GET['min']??''; $max=$_GET['max']??''; if($min!==''&&is_numeric($min)){ $where.=' AND COALESCE(sale_price,regular_price)>=?'; $params[]=$min; } if($max!==''&&is_numeric($max)){ $where.=' AND COALESCE(sale_price,regular_price)<=?'; $params[]=$max; }
$sort=$_GET['sort']??'new'; $order=$sort==='price_asc'?'COALESCE(sale_price,regular_price) ASC':($sort==='price_desc'?'COALESCE(sale_price,regular_price) DESC':'created_at DESC');
$st=$pdo->prepare("SELECT * FROM products WHERE $where ORDER BY $order"); $st->execute($params); $products=$st->fetchAll(); ?>
<section class="shop"><aside><h3>Lọc theo giá</h3><form><input type="hidden" name="cat" value="<?=htmlspecialchars($_GET['cat']??'')?>"><input name="min" placeholder="Giá tối thiểu"><input name="max" placeholder="Giá tối đa"><button>Lọc</button></form><h3>Danh mục</h3><?php foreach($cats as $c): ?><a class="side-link" href="products.php?cat=<?=$c['slug']?>"><?=$c['name']?></a><?php endforeach; ?></aside><main><div class="section-head"><h2><?=$title?></h2><form><select name="sort" onchange="this.form.submit()"><option value="new">Mới nhất</option><option value="price_asc">Giá thấp đến cao</option><option value="price_desc">Giá cao đến thấp</option></select></form></div><div class="grid"><?php foreach($products as $p): include 'product-card.php'; endforeach; ?></div></main></section><?php require 'footer.php'; ?>
